var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"50호선 고속도로라고?","JPN":"50号線の高速道路？","ENG":"I-50?","TWN":"50號線高速公路嗎？"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"그럼 국경을 넘으려던 거야? 그 고속도로는 침식지대가 길을 막아서 지날 수 없을 텐데.","JPN":"じゃあ国境を越えようとしたの？　あの高速道路は侵食地帯が道を塞いで通れないんじゃない？","ENG":"Were you trying to cross the national border? That freeway is Corrupted in the middle. You can't go through it.","TWN":"你是想穿越國界嗎？那個高速公路因為侵蝕地區的關係應該過不去吧？"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"꼬마, 쓸데없이 끼어들지 말고 운전이나 해.","JPN":"チビ、余計なこと言わないで運転に集中しろ。","ENG":"Kid, stop being nosy and keep driving.","TWN":"喂！你專心開車，插什麼嘴！"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"침식지대야 어찌됐든 네가 원하는 50호선으로 데려다 주겠어.","JPN":"侵食地帯はおいておくとして、とりあえず50号線に連れていってあげよう。","ENG":"Corrupted or not, if I-50 is where you want, we'll take you there.","TWN":"我們會想辦法把你送到那裡的！"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"우리도 이 시간엔 국경지대 근처로 순찰을 돌곤 하니까.","JPN":"俺たちもこの時間帯は国境地帯の近くをパトロールしたりするからな。","ENG":"It's about time we patrol around the national border, anyway.","TWN":"剛好每天這個時間我們也都會去國界周圍巡邏。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"그러니 걱정 말고, 앉아서 쉬어.","JPN":"だから心配しないで、そこで休んでな。","ENG":"So, don't worry and relax.","TWN":"你放心吧！先好好休息。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"아…….","JPN":"ああ……","ENG":"Oh...","TWN":"那個……"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"왜. 뭐 문제 있나?","JPN":"なんだ？　何か問題でもあるのか？","ENG":"What? Anything wrong?","TWN":"怎麼了？有什麼問題嗎？"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"앗, 아뇨.","JPN":"あっ、いいえ。","ENG":"Oh, no.","TWN":"喔，沒有。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"그게, 이런 호의를 받아보는 건 너무 오랜만이라서요.","JPN":"実は、こんなご厚意を受けるのは久しぶりで。","ENG":"It's just... I've never met such kind people for a long time.","TWN":"只是很久沒有人對我這麼好了。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"저도 참-","JPN":"私ったら。","ENG":"I know, it's weird.","TWN":"好溫暖-"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 저는 루시드라고 해요. 당신은……?","JPN":"あ、私はルシードです。あなたは……？","ENG":"Ah, I'm Lucid. You're...?","TWN":"對了，我叫露西德，請問你怎麼稱呼……？"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"됐어. 잠깐 보고 말 사이니까.","JPN":"名前なんていいさ。どうせすぐ別れるんだ。","ENG":"Forget it. It's not like we're going to be friends.","TWN":"我叫什麼名字不重要，反正我們只僅僅是一面之緣而已。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그래도…….","JPN":"でも……","ENG":"But still—","TWN":"可是……"},"stage":{"bg":"VEHICLE","bgm":"UI_LOBBY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"꺅!","JPN":"きゃっ！","ENG":"Kyaaak!","TWN":"啊！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L24_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"크윽…….","JPN":"くっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"이 빌어먹을 꼬마자식이!","JPN":"おい、クソガキ！","ENG":"You stupid kid!","TWN":"臭小子！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"차를 대체 어디 들이박는 거야!","JPN":"どこに突っ込んでんだ！","ENG":"Where did you drive the car into?","TWN":"車子現在是怎樣？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"죄, 죄송합니다! 길에 구덩이가 있을 줄은 몰라서……!","JPN":"ご、ごめんなさい！　まさか道にくぼみがあるなんて……","ENG":"S-sorry! I didn't see the pit in the middle of the road!","TWN":"對…對不起！我沒看到路上有個洞……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"……포탄이 터져서 생긴 건가?","JPN":"……砲弾の跡か？","ENG":"Is it from a shell?","TWN":"……這是被炸彈炸出來的吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"그래, 어제 공습이 있었지. 망할.","JPN":"そういえば昨日空襲があったな、ちくしょう。","ENG":"Yes, there was a raid yesterday. Drat.","TWN":"該死，一定是因為昨天的空襲！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"뭐해? 다들 내려서 차를 밀어!","JPN":"何してんだ？　全員降りて車を押せ！","ENG":"What are you doing? Get out and push the car!","TWN":"大家傻在那幹嘛？還不下去推車！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L34_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"쳇…… 돌아가면 또 한 소리 듣겠네.","JPN":"ちえっ……帰ったらまた怒られるんだろうな。","ENG":"Bah... We're not going to hear the end of it when we go back.","TWN":"嗟……回去又要被唸了！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저기, 당신은……?","JPN":"あの、あなたは……？","ENG":"Well, you...","TWN":"請問你……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"뭘 봐?","JPN":"なんだよ？","ENG":"What are you looking at?","TWN":"看什麼看？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"내가 왜 차 미는 걸 안 돕는지 묻고 싶은 거야?","JPN":"僕がなんで車を押さないのか知りたいのか？","ENG":"Are you asking why I'm not helping them push the car?","TWN":"你是不是想問我為什麼沒下去一起推車？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"신경 꺼. 널 감시하라고 어른들이 시켜서 붙어 있는 것뿐이니까.","JPN":"わざわざ聞くなよ。君を監視しろって、大人たちに言われてここにいるだけさ。","ENG":"Don't worry about me. I'm here because they want me to keep an eye on you.","TWN":"不用你雞婆！是大人要我在車上看著你的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아뇨. 전 그냥 당신의 이름을 물어보고 싶었어요.","JPN":"いいえ。私はただあなたの名前を聞きたかっただけです。","ENG":"No. I just wanted to ask you your name.","TWN":"不是的，我只是想問你叫什麼名字。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"이름? 아까도 그 얘길 듣긴 했지만, 그런 거에 꽤나 집착하네.","JPN":"名前？　さっきもその質問を聞いたけど、そんなことにかなりこだわるね。","ENG":"Name? I heard you earlier. You're pretty obsessed with other people's names.","TWN":"我的名字？你剛說的那些話我也有聽到，你還真是堅持呢！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……그런가요.","JPN":"……そうですか？","ENG":"Am I?","TWN":"……是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이름 같은 건 익숙하지 않아서요.","JPN":"名前のようなものには慣れていなくて。","ENG":"I'm not used to things like names.","TWN":"因為名字對我來說好陌生。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"예전에 그 아이의 이름을 물어보지 못했던 미련 같은 거겠죠.","JPN":"以前、あの子に名前を聞けなかった未練のようなものでしょう。","ENG":"Maybe I'm trying to make up for not asking that girl's name when I had the chance.","TWN":"可能是因為當時我沒能問那孩子的名字，這個遺憾一直在我心裡吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"어쩌면 그 아이도 저처럼 부를 이름이 없었겠지만요.","JPN":"もしかしたら、あの子も私と同じく、呼べる名前がなかったかもしれませんが。","ENG":"I doubt she had a name, though... like I didn't.","TWN":"但或許那孩子也跟我一樣是沒有名字的人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"……혼자 뭘 그렇게 중얼거리는지 원.","JPN":"……一人でぶつぶつ何言ってんだ。","ENG":"What are you mumbling to yourself?","TWN":"……你在自言自語什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"어른들은 날 핸들이라 불러.","JPN":"大人たちは僕のことをハンドルって呼んでる。","ENG":"They call me Wheel.","TWN":"大人都叫我韓德爾。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOY_NPC_REVELA_NULL","text":{"KOREA":"내가 그딴 이름을 좋아하든 싫어하든 상관없이 말이야.","JPN":"僕がその名前を好きか嫌いかなんて関係なくね。","ENG":"They don't care whether or not I like that name.","TWN":"雖然他們根本不管我喜不喜歡這個名字。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうなんですね。","ENG":"... I see.","TWN":"……原來如此。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저어.","JPN":"あの。","ENG":"Well.","TWN":"那個，"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"좀 전에 바퀴가 빠졌을 때, 짐칸에서 뭔가 빠져 나온 걸 봤어요.","JPN":"タイヤが道路のくぼみにはまった時、トランクからある物が飛び出たのを見ました。","ENG":"When the wheel came off earlier, I saw something sticking out of the trunk.","TWN":"剛才車子陷進去時，我看到有東西從車箱裡掉出來。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그건…… 사람의 팔이었어요.","JPN":"あれは……人の腕でした。","ENG":"It was... a man's arm.","TWN":"好像是……人的手臂。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그걸 봤다는 사람치곤 침착하네.","JPN":"人の腕を見たわりには落ち着いてるね。","ENG":"You sound calm for someone who saw that.","TWN":"以一個看到人手的人來說，你還滿冷靜的嘛？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"시체를 본 적은 많아요.","JPN":"死体を見たことは何度もあります。","ENG":"I've seen many corpses.","TWN":"因為我常看到屍體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"하지만, 정확한 사정을 물어보기 전까진 사람을 멋대로 판단하면 안 된다고 생각해서……","JPN":"でも詳しい事情を知らずに、勝手に人を判断してはいけないと思って……","ENG":"I just thought I shouldn't make any judgment before knowing everything there is.","TWN":"只是我覺得在沒有搞清楚事實之前，就輕易將人定罪是不好的……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"당신에게 물어보려고 했어요.","JPN":"あなたに聞いてみようと思ったのです。","ENG":"So, I wanted to ask you.","TWN":"所以才想問你。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"네가 본 건 반군들이야.","JPN":"君が見たのは反乱軍だ。","ENG":"What you saw is a dead rebel.","TWN":"你看到的那條手是叛軍的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"반군이 정부군 차를 훔쳐 달아나는 걸 발견해서 어른들이 쐈어.","JPN":"反乱軍が政府軍の車を盗んで逃げようとしたのを発見して、大人たちが撃ったんだ。","ENG":"Some rebels tried to steal a government vehicle, so we shot them down.","TWN":"大人發現叛軍劫持政府軍的車，於是就射殺他們。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"차에 싣고 온 건, 시체를 그냥 내버려 두면 침식체가 된다는 미신 때문이고.","JPN":"車に積んでいたのは、そのまま死体を放っておくと侵食体になるっていう迷信があるからさ。","ENG":"They brought the bodies in the car because of superstition. They believe dead bodies become C.O.s if not taken care of.","TWN":"之所以會屍體放車上，是因為傳言亂丟會變成侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"자, 이제 됐지?","JPN":"これでいいかい？","ENG":"Well, are you happy now?","TWN":"這樣可以了吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런…….","JPN":"そんな……","ENG":"That's...","TWN":"嗯……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"잘 모르겠어요.","JPN":"よくわかりません。","ENG":"I don't know.","TWN":"我不是很明白，"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"고작 그런 이유로 같은 사람끼리 서로를 해치다니.","JPN":"たかがそんな理由で、人間同士がお互いを傷つけるなんて。","ENG":"I don't think people should kill each other for a reason like that.","TWN":"人為什麼可以因為這樣的理由就互相殘殺。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"쳇, 대체 무슨 소릴 하는 거야?","JPN":"は？　何を言ってるんだ？","ENG":"Sheesh, what the hell are you talking about?","TWN":"哇咧，你到底在胡說八道什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"사람들끼리 다 같은 편일 리 있나.","JPN":"人間同士がみんな味方なわけないだろ。","ENG":"Not everyone is on the same side.","TWN":"就算都是人，立場也不可能都一樣吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"이빨을 달고 태어났으면 서로 물어뜯는 게 당연하다고.","JPN":"やられる前にやるのは当然のことさ。","ENG":"Anything that has teeth bites at others. It's only natural.","TWN":"人之所以有牙齒，不就是要彼此互咬嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"역시 전 혼자 가는 편이 좋겠어요.","JPN":"やっぱり私は一人で行ったほうがよさそうです。","ENG":"I think I should go alone.","TWN":"我看我還是自己去吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"태워 주지 않으셔도 돼요. 저 혼자서도 갈 수 있으니까.","JPN":"もう車に乗せてもらわなくても大丈夫です。私一人でも行けますので。","ENG":"You don't have to give me a ride. I can get there by myself.","TWN":"不用麻煩你們，我可以自己去。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"50호선 고속도로로 가는 길만 알려 주세요.","JPN":"50号線高速道路への道だけ教えてください。","ENG":"Please tell me how to get to I-50.","TWN":"請告訴我50號線高速公路要怎麼走就好。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그건 안 돼. 그건 내가 정할 수 있는 게 아니라고.","JPN":"それはダメだ。僕が決められることじゃないって。","ENG":"No, that's not something I can decide.","TWN":"那可不行，這不是我能決定的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"가면 안 된다고 했잖아, 멈춰!","JPN":"勝手に行くなって言っただろ。止まれ！","ENG":"I said, no. Stop!","TWN":"我不是說了不可以嗎！站住！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"싫어! 이거 놔 줘요!","JPN":"嫌です！　離してください！","ENG":"No! Let me go!","TWN":"我不要！放開我！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"매복이다!","JPN":"待ち伏せだ！","ENG":"Ambush!","TWN":"有埋伏！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"반군이 습격한다!","JPN":"反乱軍の襲撃だ！","ENG":"The rebels have struck!","TWN":"叛軍突襲我們！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"정부군들은 다 죽여!","JPN":"政府軍は皆殺しにしろ！","ENG":"Kill all the government forces!","TWN":"殺光那些政府軍！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"동포들의 복수를 하자!","JPN":"同胞の仇を討て！","ENG":"Let's avenge our friends!","TWN":"替我們的夥伴報仇！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_TOUCH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"방금 그건……","JPN":"今のは……","ENG":"That's...","TWN":"你剛剛……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"당신. 거짓말이었군요.","JPN":"あなた、嘘をついていたのですね。","ENG":"You. You lied to me.","TWN":"說謊騙人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"뭐, 뭐?","JPN":"な、なんだって？","ENG":"Wh-what?","TWN":"什…什麼騙人？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"반군은…… 지금 정부군의 차를 빼앗아 타고 있는 당신들이었어요.","JPN":"反乱軍は……今、政府軍の車を奪って乗っていたあなたたちでした。","ENG":"You're the rebels. You stole this government car.","TWN":"劫持政府軍車輛的叛軍……就是你們。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"어떻게 그걸……","JPN":"なんで、それを……","ENG":"How did you...","TWN":"你怎麼……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그, 그래서 그게 뭐 어쨌다는 건데?","JPN":"そ、それがどうしたっていうんだ？","ENG":"S-so, what?","TWN":"那你想怎麼樣？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"정말 저희가 국경으로 가고 있는 게 맞는 건가요?","JPN":"本当に私たちは国境に向かっているのですか？","ENG":"Are we even going to the national border right now?","TWN":"我們真的是往國界的方向前進嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"지금이라도 절 보내 주세요. 부탁할게요.","JPN":"今からでも私を行かせてください。お願いします。","ENG":"It's not too late to let me go. Please.","TWN":"請放了我吧，拜託你。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"……그건 곤란해.","JPN":"……それは困るんだ。","ENG":"... Can't.","TWN":"……沒辦法。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"내 동생이 반군들 주둔지에 있어. 널 풀어줬다간 동생까지 위험해져.","JPN":"僕の弟が反乱軍の駐屯地にいる。君を逃がしたら弟まで危なくなる。","ENG":"My brother is in the rebels' camp. I can't risk his life by letting you go.","TWN":"我弟弟還在叛軍營區裡，放了你我弟弟會有麻煩的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"안내까진 바라지도 않아요. 저 혼자서 갈 테니까 길만 가르쳐 주시면……","JPN":"案内してほしいとまでは言いません。私一人で行くので、道だけ教えてくれれば……","ENG":"You don't have to show me the way. I can go by myself. Just tell me where to go—","TWN":"我不奢望你帶我去，只要告訴我怎麼走就好……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 또 무슨 상황이야?","JPN":"これはまたどういう状況だ？","ENG":"What's going on here?","TWN":"現在是在演哪齣？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"여잘 감시하고 있으랬더니 무슨 드라마를 찍고 있구만.","JPN":"女を監視してろと言ったはずだが、ドラマでも撮ってんのか？","ENG":"I told you to watch the girl, not film a movie with her.","TWN":"我叫你監視這個女的，結果你給我演起愛情劇啊？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"대, 대장…….","JPN":"た、隊長……","ENG":"C-Captain...","TWN":"隊…隊長…。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"<color=#ffd34c>상품</color>이 하는 말에 휘둘리는 거냐, 핸들.","JPN":"<color=#ffd34c>商品</color>の言うことに振り回されてどうすんだ、ハンドル。","ENG":"You're letting the <color=#ffd34c>product</color> sway you, Wheel.","TWN":"你怎麼可以被<color=#ffd34c>商品</color>的話左右呢？韓德爾。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"정신 차려. 그런 물렁한 생각으로는 약한 것들에게 먹혀 버릴 뿐이야.","JPN":"しっかりしろ。そんな頭の中がお花畑な思考じゃ、弱い者に食われちまうぞ。","ENG":"Get a grip. Being so soft, you'll get eaten alive by those who are weaker than you.","TWN":"給我清醒一點！心軟是無法成什麼大事的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"상품…… 이라고요?","JPN":"商品……ですか？","ENG":"A... product?","TWN":"你說……商品？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"아, 그리고 너.","JPN":"あ、それからお前。","ENG":"Oh, and you.","TWN":"還有你！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"얌전히 있었다면 묶진 않으려 했는데, 이젠 안 되겠어.","JPN":"大人しくしていたら縛るつもりはなかったんだが、もうダメだな。","ENG":"We didn't think we needed to tie you up, but we should.","TWN":"只要你乖乖的，我本來是沒有想把你綁起來的，但看來不綁不行！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"당신들도 결국……","JPN":"あなたたちも結局……","ENG":"In the end, you...","TWN":"結果……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"절 어딘가에 팔아 넘기려고 했던 거군요.","JPN":"私をどこかに売り渡そうとしたのですね。","ENG":"You were going to sell me away.","TWN":"你們也是想把我賣到某個地方去嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"어째서죠? 절 데려다 주겠다던 호의도 거짓이었던 건가요?!","JPN":"どうしてですか？　私を目的地まで連れて行ってくれるという好意も嘘だったんですか！？","ENG":"Why? Were you lying about taking me where I wanted, too?","TWN":"怎麼會這樣？所以你們剛才說要帶我去高速公路也是假的嗎？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"꺄악……!","JPN":"きゃっ……！","ENG":"Kyaak!","TWN":"啊……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"정부에 빌붙으려는 난민 주제에 주절주절 시끄러워.","JPN":"政府にしがみつこうとする難民のくせに、ぶつぶつうるせえな。","ENG":"Shut up. You're just another refugee living off the government.","TWN":"吵死了！想要投靠政府的難民廢話還真多！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"어이! 묶어둘 것 좀 가져와!","JPN":"おい！　縛れそうな物を持ってこい！","ENG":"Hey! Bring me something to tie her with!","TWN":"喂！找找看有沒有什麼東西可以拿來綁住她！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"저기…… 대장.","JPN":"あのさ……隊長。","ENG":"Hey... Captain.","TWN":"那個……隊長。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"귀 먹었어? 줄을 가져오라고!","JPN":"聞いてんのか？　ロープを持ってこい！","ENG":"Didn't you hear me? Bring me a rope!","TWN":"你耳聾啦？我叫你拿繩子來沒聽到嗎！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"……저, 저쪽에 검은 녀석들이!","JPN":"……あ、あっちに黒いやつらが！","ENG":"D-dark things are coming this way!","TWN":"……你看那邊！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"흐히익! 침식체다!","JPN":"ヒッ！　侵食体だ！","ENG":"Heek! C.O.s!","TWN":"啊啊！是侵蝕體！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"빌어먹을, 하필 이럴 때……!","JPN":"くそっ、よりによってこんな時に……！","ENG":"Drat, why now!","TWN":"可惡，真不會挑時間……！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"무기를 들어! 몇 놈 없으니 머릿수로 밀어 버려!","JPN":"武器を構えろ！　多くはないからこっちの数で押しちまえ！","ENG":"Raise your weapon! There are more of us than them. Let's wipe them out!","TWN":"拿武器！它們數量不多，我們有人數優勢！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};